#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define LIMIT -999
#define BLOCK_SIZE 16

int maximum(int a, int b, int c) {
    int k;
    if (a <= b)
        k = b;
    else
        k = a;
    if (k <= c)
        return c;
    else
        return k;
}

__kernel void nw_kernel1(__global int* referrence,
                        __global int* input_itemsets,
                        __global int* output_itemsets,
                        __local int* input_itemsets_l,
                        __local int* reference_l,
                        const int max_cols,
                        const int penalty,
                        const int blk,
                        const int block_width,
                        const int worksize,
                        const int offset_r,
                        const int offset_c)
{
    int b_index_x = get_global_id(0) / BLOCK_SIZE;
    if (b_index_x >= blk) return;
    int b_index_y = blk - 1 - b_index_x;

    int local_id = get_local_id(0);
    int local_size = get_local_size(0);

    // Load reference_l (BLOCK_SIZE x BLOCK_SIZE) into local memory
    for (int i = local_id; i < BLOCK_SIZE * BLOCK_SIZE; i += local_size) {
        int row = i / BLOCK_SIZE;
        int col = i % BLOCK_SIZE;
        reference_l[i] = referrence[max_cols * (b_index_y * BLOCK_SIZE + row + 1) + b_index_x * BLOCK_SIZE + col + 1];
    }

    // Load input_itemsets_l ((BLOCK_SIZE+1) x (BLOCK_SIZE+1)) into local memory
    for (int i = local_id; i < (BLOCK_SIZE + 1) * (BLOCK_SIZE + 1); i += local_size) {
        int row = i / (BLOCK_SIZE + 1);
        int col = i % (BLOCK_SIZE + 1);
        input_itemsets_l[i] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + row) + b_index_x * BLOCK_SIZE + col];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute the block
    for (int i = 1; i <= BLOCK_SIZE; i++) {
        for (int j = 1; j <= BLOCK_SIZE; j++) {
            int val = maximum(
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j - 1] + reference_l[(i - 1) * BLOCK_SIZE + j - 1],
                input_itemsets_l[i * (BLOCK_SIZE + 1) + j - 1] - penalty,
                input_itemsets_l[(i - 1) * (BLOCK_SIZE + 1) + j] - penalty);
            input_itemsets_l[i * (BLOCK_SIZE + 1) + j] = val;
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Write back to global memory
    for (int i = local_id; i < BLOCK_SIZE * BLOCK_SIZE; i += local_size) {
        int row = i / BLOCK_SIZE;
        int col = i % BLOCK_SIZE;
        input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + row + 1) + b_index_x * BLOCK_SIZE + col + 1] =
            input_itemsets_l[(row + 1) * (BLOCK_SIZE + 1) + col + 1];
    }
}

